import{_ as e}from"./chunks/cloudflare api token截图.cXTahxtC.js";import{_ as i}from"./chunks/查看全局令牌.BhcACLhK.js";import{_ as l,o as n,c as t,a2 as r}from"./chunks/framework.DnrXFDHb.js";const b=JSON.parse('{"title":"Cloudflare API Token","description":"","frontmatter":{},"headers":[],"relativePath":"id-ID/Safety/cloudflare-api-token.md","filePath":"id-ID/Safety/cloudflare-api-token.md","lastUpdated":1781962217000}'),o={name:"id-ID/Safety/cloudflare-api-token.md"};function d(s,a,p,u,h,c){return n(),t("div",null,[...a[0]||(a[0]=[r('<h1 id="cloudflare-api-token" tabindex="-1">Cloudflare API Token <a class="header-anchor" href="#cloudflare-api-token" aria-label="Permalink to &quot;Cloudflare API Token&quot;">​</a></h1><p>Cloudflare API credentials memungkinkan ImgBed purge Cloudflare CDN cache setelah files berubah.</p><p><img src="'+e+'" alt="Cloudflare API Token settings" loading="lazy"></p><h2 id="di-mana-mengonfigurasinya" tabindex="-1">Di Mana Mengonfigurasinya <a class="header-anchor" href="#di-mana-mengonfigurasinya" aria-label="Permalink to &quot;Di Mana Mengonfigurasinya&quot;">​</a></h2><p>Buka admin panel, lalu masuk ke:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Cloudflare API Token</span></span></code></pre></div><p>Anda perlu mengisi:</p><ul><li>Zone ID</li><li>Account email</li><li>API Key</li></ul><h2 id="fungsi-setting-ini" tabindex="-1">Fungsi Setting Ini <a class="header-anchor" href="#fungsi-setting-ini" aria-label="Permalink to &quot;Fungsi Setting Ini&quot;">​</a></h2><p>Cloudflare dapat cache public image URLs.</p><p>Caching membuat image delivery lebih cepat, tetapi juga bisa membuat content lama tetap terlihat beberapa saat setelah Anda delete, block, replace, atau move file.</p><p>Setelah Cloudflare API credentials dikonfigurasi, ImgBed mencoba purge Cloudflare cache terkait saat operasi tersebut selesai.</p><p>Ini berguna saat:</p><ul><li>Anda delete image dan ingin public link berhenti bekerja secepat mungkin.</li><li>Anda block image dan ingin visitors berhenti melihat original file.</li><li>Anda replace file dengan nama yang sama dan ingin visitors melihat versi baru lebih cepat.</li><li>Anda move atau rename files dan ingin old path cache refresh lebih cepat.</li><li>Anda mengubah public access rules dan ingin public gallery atau random image cache update lebih cepat.</li></ul><h2 id="jika-dibiarkan-kosong" tabindex="-1">Jika Dibiarkan Kosong <a class="header-anchor" href="#jika-dibiarkan-kosong" aria-label="Permalink to &quot;Jika Dibiarkan Kosong&quot;">​</a></h2><p>ImgBed tetap berjalan normal tanpa setting ini.</p><p>Perbedaannya, ImgBed tidak akan actively purge Cloudflare CDN cache. Visitors mungkin tetap melihat content lama sampai Cloudflare cache expire secara alami.</p><h2 id="cara-menemukan-zone-id" tabindex="-1">Cara Menemukan Zone ID <a class="header-anchor" href="#cara-menemukan-zone-id" aria-label="Permalink to &quot;Cara Menemukan Zone ID&quot;">​</a></h2><p>Zone ID adalah Cloudflare Zone ID dari site yang dipakai oleh ImgBed domain Anda.</p><ol><li>Sign in ke Cloudflare dashboard.</li><li>Buka site yang berisi ImgBed domain Anda.</li><li>Cari <code>Zone ID</code> di site overview page.</li><li>Copy ke field <code>Zone ID</code> di ImgBed.</li></ol><p>Ini adalah site Zone ID, bukan account ID.</p><h2 id="account-email" tabindex="-1">Account Email <a class="header-anchor" href="#account-email" aria-label="Permalink to &quot;Account Email&quot;">​</a></h2><p>Masukkan email address yang Anda gunakan untuk sign in ke Cloudflare.</p><p>Email ini harus cocok dengan API Key di bawah.</p><h2 id="api-key" tabindex="-1">API Key <a class="header-anchor" href="#api-key" aria-label="Permalink to &quot;API Key&quot;">​</a></h2><p>Masukkan Cloudflare Global API Key.</p><ol><li>Sign in ke Cloudflare dashboard.</li><li>Buka profile.</li><li>Masuk ke API Tokens page.</li><li>Cari <code>Global API Key</code>.</li><li>View dan copy.</li><li>Paste ke field <code>API Key</code> di ImgBed.</li></ol><p><img src="'+i+'" alt="View global API key" loading="lazy"></p><h2 id="kapan-berlaku" tabindex="-1">Kapan Berlaku <a class="header-anchor" href="#kapan-berlaku" aria-label="Permalink to &quot;Kapan Berlaku&quot;">​</a></h2><p>Setelah field diisi, save settings.</p><p>File changes setelah itu akan otomatis mencoba purge Cloudflare cache. Past operations tidak dipurge secara retroaktif. Jika Anda delete atau replace file sebelum setup ini, tunggu Cloudflare cache expire atau purge manual di Cloudflare.</p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="apakah-ini-wajib" tabindex="-1">Apakah Ini Wajib? <a class="header-anchor" href="#apakah-ini-wajib" aria-label="Permalink to &quot;Apakah Ini Wajib?&quot;">​</a></h3><p>Tidak.</p><p>Jika domain Anda tidak memakai Cloudflare, atau Anda tidak masalah dengan CDN cache delay, biarkan kosong.</p><h3 id="apakah-credentials-salah-akan-merusak-uploads" tabindex="-1">Apakah Credentials Salah Akan Merusak Uploads? <a class="header-anchor" href="#apakah-credentials-salah-akan-merusak-uploads" aria-label="Permalink to &quot;Apakah Credentials Salah Akan Merusak Uploads?&quot;">​</a></h3><p>Biasanya tidak.</p><p>Credentials salah hanya membuat ImgBed gagal purge Cloudflare cache. Upload dan normal file access seharusnya tetap berjalan.</p><h3 id="mengapa-deleted-image-masih-bisa-dibuka" tabindex="-1">Mengapa Deleted Image Masih Bisa Dibuka? <a class="header-anchor" href="#mengapa-deleted-image-masih-bisa-dibuka" aria-label="Permalink to &quot;Mengapa Deleted Image Masih Bisa Dibuka?&quot;">​</a></h3><p>Penyebab paling umum adalah Cloudflare masih menyimpan file lama di cache.</p><p>Dengan Cloudflare API credentials yang benar, ImgBed purge related URL cache saat file dihapus.</p><h3 id="mengapa-setelah-replace-file-masih-melihat-image-lama" tabindex="-1">Mengapa Setelah Replace File Masih Melihat Image Lama? <a class="header-anchor" href="#mengapa-setelah-replace-file-masih-melihat-image-lama" aria-label="Permalink to &quot;Mengapa Setelah Replace File Masih Melihat Image Lama?&quot;">​</a></h3><p>Ini juga biasanya disebabkan CDN cache.</p><p>Setelah setting ini dikonfigurasi, ImgBed mencoba purge old URL cache saat file dengan nama yang sama dioverwrite.</p>',44)])])}const f=l(o,[["render",d]]);export{b as __pageData,f as default};
